<?phpdeclare(strict_types=1);require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/SessionManager.php';require_once__DIR__.'/../core/auth_helper.php';require_once__DIR__.'/../core/DatabaseOptimizer.php';/Authenticationcheckif(!AuthHelper::validateSession()){header('Location:'.url('login.php'));exit;}$page_title='MonitoringDashboard-SPRIN';include__DIR__.'/../includes/components/header.php';?><divclass="containermt-4"><divclass="row"><divclass="col-12"><h1>📊MonitoringDashboard</h1><pclass="text-muted">Real-timesystemmonitoringandperformancemetrics</p></div></div><!--SystemHealth--><divclass="rowmb-4"><divclass="col-md-3"><divclass="cardtext-center"><divclass="card-body"><h5class="card-title">Database</h5><divclass="system-status"id="db-status"><divclass="spinner-bordertext-primary"role="status"><spanclass="visually-hidden">Loading...</span></div></div></div></div></div><divclass="col-md-3"><divclass="cardtext-center"><divclass="card-body"><h5class="card-title">APIStatus</h5><divclass="system-status"id="api-status"><divclass="spinner-bordertext-primary"role="status"><spanclass="visually-hidden">Loading...</span></div></div></div></div></div><divclass="col-md-3"><divclass="cardtext-center"><divclass="card-body"><h5class="card-title">Performance</h5><divclass="system-status"id="perf-status"><divclass="spinner-bordertext-primary"role="status"><spanclass="visually-hidden">Loading...</span></div></div></div></div></div><divclass="col-md-3"><divclass="cardtext-center"><divclass="card-body"><h5class="card-title">Security</h5><divclass="system-status"id="security-status"><divclass="spinner-bordertext-primary"role="status"><spanclass="visually-hidden">Loading...</span></div></div></div></div></div></div><!--PerformanceMetrics--><divclass="rowmb-4"><divclass="col-md-6"><divclass="card"><divclass="card-header"><h5class="card-title">PerformanceMetrics</h5></div><divclass="card-body"><canvasid="performance-chart"width="400"height="200"></canvas></div></div></div><divclass="col-md-6"><divclass="card"><divclass="card-header"><h5class="card-title">SystemResources</h5></div><divclass="card-body"><divid="system-resources"><divclass="mb-3"><label>MemoryUsage</label><divclass="progress"><divclass="progress-bar"id="memory-usage"role="progressbar"style="width:0%">0%</div></div></div><divclass="mb-3"><label>CPUUsage</label><divclass="progress"><divclass="progress-bar"id="cpu-usage"role="progressbar"style="width:0%">0%</div></div></div></div></div></div></div></div><!--RecentLogs--><divclass="row"><divclass="col-12"><divclass="card"><divclass="card-headerd-flexjustify-content-betweenalign-items-center"><h5class="card-title">RecentActivity</h5><buttonclass="btnbtn-smbtn-outline-primary"onclick="refreshLogs()"><iclass="fasfa-sync"></i>Refresh</button></div><divclass="card-body"><divid="activity-log"><divclass="text-center"><divclass="spinner-bordertext-primary"role="status"><spanclass="visually-hidden">Loading...</span></div></div></div></div></div></div></div></div><scriptsrc="https://cdn.jsdelivr.net/npm/chart.js"></script><script>/Initializemonitoringdashboarddocument.addEventListener('DOMContentLoaded',function(){loadSystemHealth();loadPerformanceMetrics();loadActivityLog();/Auto-refreshevery30secondssetInterval(function(){loadSystemHealth();loadPerformanceMetrics();},30000);});functionloadSystemHealth(){fetch('/api/health_check_new.php').then(response=>response.json()).then(data=>{updateSystemStatus('db-status',data.checks.database?'success':'danger',data.checks.database?'Connected':'Disconnected');updateSystemStatus('api-status',data.checks.api?'success':'danger',data.checks.api?'Working':'Issues');updateSystemStatus('perf-status',data.checks.performance===true?'success':(data.checks.performance==='warning'?'warning':'danger'),data.checks.performance===true?'Good':(data.checks.performance==='warning'?'Slow':'Poor'));updateSystemStatus('security-status',data.checks.security?'success':'danger',data.checks.security?'Secure':'Issues');}).catch(error=>{console.error('Errorloadingsystemhealth:',error);});}functionupdateSystemStatus(elementId,status,text){constelement=document.getElementById(elementId);element.innerHTML=`<divclass="alertalert-${status}"><iclass="fasfa-${status==='success'?'check-circle':'exclamation-triangle'}"></i>${text}</div>`;}functionloadPerformanceMetrics(){fetch('/api/performance_metrics.php').then(response=>response.json()).then(data=>{updatePerformanceChart(data);updateSystemResources(data);}).catch(error=>{console.error('Errorloadingperformancemetrics:',error);});}functionupdatePerformanceChart(data){constctx=document.getElementById('performance-chart').getContext('2d');if(window.performanceChart){window.performanceChart.destroy();}window.performanceChart=newChart(ctx,{type:'line',data:{labels:data.labels||[],datasets:[{label:'ResponseTime(ms)',data:data.response_times||[],borderColor:'rgb(75,192,192)',tension:0.1}]},options:{responsive:true,scales:{y:{beginAtZero:true}}}});}functionupdateSystemResources(data){if(data.memory_usage){document.getElementById('memory-usage').style.width=data.memory_usage+'%';document.getElementById('memory-usage').textContent=data.memory_usage+'%';}if(data.cpu_usage){document.getElementById('cpu-usage').style.width=data.cpu_usage+'%';document.getElementById('cpu-usage').textContent=data.cpu_usage+'%';}}functionloadActivityLog(){fetch('/api/activity_log.php').then(response=>response.json()).then(data=>{constlogContainer=document.getElementById('activity-log');if(data.length===0){logContainer.innerHTML='<pclass="text-muted">Norecentactivity</p>';return;}lethtml='<divclass="timeline">';data.forEach(item=>{html+=`<divclass="timeline-itemmb-3"><divclass="timeline-marker"><iclass="fasfa-${item.type}"></i></div><divclass="timeline-content"><h6>${item.action}</h6><pclass="text-mutedsmall">${item.details}</p><smallclass="text-muted">${item.timestamp}</small></div></div>`;});html+='</div>';logContainer.innerHTML=html;}).catch(error=>{console.error('Errorloadingactivitylog:',error);});}functionrefreshLogs(){loadActivityLog();showNotification('Activitylogrefreshed','success');}</script><style>.system-status.alert{margin-bottom:0;padding:10px;}.timeline{position:relative;padding-left:30px;}.timeline::before{content:'';position:absolute;left:10px;top:0;bottom:0;width:2px;background:#ddd;}.timeline-item{position:relative;}.timeline-marker{position:absolute;left:-30px;top:0;width:20px;height:20px;border-radius:50%;background:white;border:2pxsolid#ddd;display:flex;align-items:center;justify-content:center;font-size:10px;}.timeline-content{background:white;padding:15px;border-radius:8px;box-shadow:02px4pxrgba(0,0,0,0.1);}</style><?phpinclude__DIR__.'/../includes/components/footer.php';?>
